import sys
import ast
from functools import lru_cache
from itertools import combinations

def solve() -> None:
    line = sys.stdin.readline().strip()
    if not line:
        return
    # Parse list like "[1, 2, 3]"
    try:
        dice = ast.literal_eval(line)
    except Exception:
        # fallback: split numbers
        dice = list(map(int, line.strip('[]').split(',')))
    # Count faces 1..6
    counts = [0] * 7
    for d in dice:
        if 1 <= d <= 6:
            counts[d] += 1

    base_score = [0] * 7
    for f in range(1, 7):
        base_score[f] = 1000 if f == 1 else f * 100

    @lru_cache(None)
    def dfs(state):
        # state is a tuple of counts[1..6]
        best = 0
        cnt = list(state)

        # Straight (1-6)
        if all(c >= 1 for c in cnt[1:]):
            new_state = tuple(cnt[i] - 1 for i in range(1, 7))
            best = max(best, 1500 + dfs(new_state))

        # Three pairs
        faces_with_two = [i for i in range(1, 7) if cnt[i] >= 2]
        if len(faces_with_two) >= 3:
            # try all combinations of three faces
            for trio in combinations(faces_with_two, 3):
                new_cnt = cnt[:]
                for f in trio:
                    new_cnt[f] -= 2
                new_state = tuple(new_cnt[1:])
                best = max(best, 750 + dfs(new_state))

        # k-of-a-kind (k from 3 to 6)
        for f in range(1, 7):
            for k in range(3, 7):
                if cnt[f] >= k:
                    mult = k - 2  # 3->1,4->2,5->3,6->4
                    score = base_score[f] * mult
                    new_cnt = cnt[:]
                    new_cnt[f] -= k
                    new_state = tuple(new_cnt[1:])
                    best = max(best, score + dfs(new_state))

        # Single 1
        if cnt[1] > 0:
            new_cnt = cnt[:]
            new_cnt[1] -= 1
            best = max(best, 100 + dfs(tuple(new_cnt[1:])))

        # Single 5
        if cnt[5] > 0:
            new_cnt = cnt[:]
            new_cnt[5] -= 1
            best = max(best, 50 + dfs(tuple(new_cnt[1:])))

        return best

    max_score = dfs(tuple(counts[1:]))
    if max_score == 0:
        print("Zonk")
    else:
        print(max_score)


if __name__ == "__main__":
    solve()

