def transform(s: str) -> str:
    res = []
    i = 0
    n = len(s)
    while i < n:
        if s[i] == ' ':
            # copy spaces as they are
            res.append(s[i])
            i += 1
        else:
            # start of a word
            j = i
            while j < n and s[j] != ' ':
                j += 1
            word = s[i:j]
            if len(word) > 2:
                word = word[0].upper() + word[1:].lower()
            # else keep original word unchanged
            res.append(word)
            i = j
    return ''.join(res)

