        return
    n = int(data[0])

    # Pisano period for modulo 10 is 60
    period = 60
    idx = n % period
    if idx == 0:
        idx = period

    # Compute Fibonacci numbers modulo 10 up to idx
    # F1 = 1, F2 = 1
    if idx <= 2:
        result = 1
    else:
        a, b = 1, 1  # F1, F2
        for _ in range(3, idx + 1):
            a, b = b, (a + b) % 10
        result = b % 10

