def solve() -> None:
    s = sys.stdin.readline().strip()
    vowels = {'a', 'e', 'i', 'o', 'u'}
    bad = {'c', 'o', 'd', 'e'}

    res = []
    for ch in s:
        # decide shift
        if ch == 'c' or ch == 'o':
            shift = -1
        elif ch == 'd':
            shift = -3
        elif ch == 'e':
            shift = -4
        else:
            if ch in vowels:
                shift = -5
            else:
                shift = 9

        # apply circular shift
        pos = ord(ch) - ord('a')
        new_pos = (pos + shift) % 26
        new_ch = chr(new_pos + ord('a'))

        # revert if new character is forbidden
        if new_ch in bad:
            res.append(ch)
        else:
            res.append(new_ch)

    sys.stdout.write(''.join(res))

