def can_be_strictly_increasing(seq):
    removals = 0
    n = len(seq)
    for i in range(1, n):
        if seq[i] <= seq[i - 1]:
            removals += 1
            if removals > 1:
                return False
            # Check if we can remove seq[i-1] or seq[i]
            if i == 1 or seq[i] > seq[i - 2]:
                # pretend seq[i-1] removed, continue
                continue
            elif i + 1 == n or seq[i + 1] > seq[i - 1]:
                # pretend seq[i] removed, skip next comparison by setting seq[i] = seq[i-1]
                seq[i] = seq[i - 1]
            else:
                return False
    return True

