def can_fit(a: int, b: int, m: int, n: int) -> bool:
    # Check horizontal placement: squares side by side along width m, height limited by n
    if max(a, b) <= n and a + b <= m:
        return True
    # Check vertical placement: squares stacked along height n, width limited by m
    if max(a, b) <= m and a + b <= n:
        return True
    return False

