import sys

def valid_number(s: str) -> bool:
    """Check leading zero rules (no leading zeros unless the number is exactly 0)."""
    if s == "-0":
        return False
    if s[0] == '-':
        core = s[1:]
        if not core:
            return False
        if core[0] == '0' and len(core) > 1:
            return False
    else:
        if s[0] == '0' and len(s) > 1:
            return False
    return True

