    line = sys.stdin.readline().strip().lower()
    # Replace hyphens with spaces to handle cases like "twenty-one"
    line = line.replace('-', ' ')
    tokens = line.split()

    # Mapping of word to its numeric value
    units = {
        "zero": 0, "one": 1, "two": 2, "three": 3, "four": 4,
        "five": 5, "six": 6, "seven": 7, "eight": 8, "nine": 9,
        "ten": 10, "eleven": 11, "twelve": 12, "thirteen": 13,
        "fourteen": 14, "fifteen": 15, "sixteen": 16, "seventeen": 17,
        "eighteen": 18, "nineteen": 19
    }

    tens = {
        "twenty": 20, "thirty": 30, "forty": 40, "fifty": 50,
        "sixty": 60, "seventy": 70, "eighty": 80, "ninety": 90
    }

    multipliers = {
        "hundred": 100,
        "thousand": 1000,
        "million": 1_000_000
    }

    total = 0
    current = 0

    for token in tokens:
        if token == "and":
            continue
        if token in units:
            current += units[token]
        elif token in tens:
            current += tens[token]
        elif token == "hundred":
            current *= multipliers[token]
        elif token in ("thousand", "million"):
            # Apply multiplier to the current part and add to total
            total += current * multipliers[token]
            current = 0
        else:
            # Unexpected token (should not happen per problem statement)
            pass

    total += current
    print(total)

