def factorize(n: int):
    """Return a dict of prime -> exponent for n."""
    factors = {}
    d = 2
    while d * d <= n:
        while n % d == 0:
            factors[d] = factors.get(d, 0) + 1
            n //= d
        d += 1 if d == 2 else 2  # after 2, check only odd numbers
    if n > 1:
        factors[n] = factors.get(n, 0) + 1
    return factors

