def next_smaller(num_str: str) -> str:
    digits = list(num_str)
    n = len(digits)

    # Scan from right to left to find the first position that can be decreased
    for i in range(n - 2, -1, -1):
        # Find the largest digit smaller than digits[i] in the suffix
        max_smaller = None
        idx = -1
        for j in range(i + 1, n):
            if digits[j] < digits[i]:
                if max_smaller is None or digits[j] > max_smaller or (digits[j] == max_smaller and j > idx):
                    max_smaller = digits[j]
                    idx = j
        if max_smaller is not None:
            # If swapping would put a leading zero, skip this candidate
            if i == 0 and max_smaller == '0':
                continue
            # Perform swap
            digits[i], digits[idx] = digits[idx], digits[i]
            # Sort the suffix in descending order to get the maximal number
            digits[i + 1:] = sorted(digits[i + 1:], reverse=True)
            result = ''.join(digits)
            # Ensure no leading zero (should already be handled)
            if result[0] == '0':
                return "-1"
            return result
    return "-1"

