def is_square(x: int) -> bool:
    r = int(math.isqrt(x))
    return r * r == x

def min_squares(n: int) -> int:
    # 1 square
    if is_square(n):
        return 1

    # 2 squares
    limit = int(math.isqrt(n))
    for a in range(1, limit + 1):
        if is_square(n - a * a):
            return 2

    # Reduce n by removing factors of 4
    m = n
    while m % 4 == 0:
        m //= 4

    # 4 squares condition (Legendre's theorem)
    if m % 8 == 7:
        return 4

    # Otherwise 3 squares are enough
    return 3

