def totient(n: int) -> int:
    if n == 1:
        return 0
    result = n
    temp = n
    # factor 2
    if temp % 2 == 0:
        result -= result // 2
        while temp % 2 == 0:
            temp //= 2
    # odd factors
    p = 3
    limit = math.isqrt(temp) + 1
    while p <= limit and temp > 1:
        if temp % p == 0:
            result -= result // p
            while temp % p == 0:
                temp //= p
            limit = math.isqrt(temp) + 1
        p += 2
    # if remaining prime factor
    if temp > 1:
        result -= result // temp
    return result

