def evaluate_derivative(poly: str, x: int) -> int:
    # Insert '+' before any '-' to simplify splitting
    poly = poly.replace('-', '+-')
    terms = poly.split('+')
    result = 0
    for term in terms:
        if not term:
            continue
        # Skip constant terms (no 'x')
        if 'x' not in term:
            continue

        # Find coefficient
        x_pos = term.find('x')
        coeff_part = term[:x_pos]
        if coeff_part == '' or coeff_part == '+':
            coeff = 1
        elif coeff_part == '-':
            coeff = -1
        else:
            coeff = int(coeff_part)

        # Find exponent
        if '^' in term:
            exp = int(term.split('^')[1])
        else:
            exp = 1

        # Derivative of a*x^b is (a*b)*x^(b-1)
        new_coeff = coeff * exp
        new_exp = exp - 1
        result += new_coeff * (x ** new_exp)
    return result


