import heapq

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    n = int(next(it))
    d = int(next(it))

    # gains: index 0..n-1, gain[0]=gain[n-1]=0
    gain = [0] * n
    for i in range(1, n - 1):
        gain[i] = int(next(it))

    x = [0] * n
    y = [0] * n
    for i in range(n):
        x[i] = int(next(it))
        y[i] = int(next(it))

    # pre‑compute Manhattan distances multiplied by d
    cost = [[0] * n for _ in range(n)]
    for i in range(n):
        for j in range(n):
            if i == j:
                continue
            man = abs(x[i] - x[j]) + abs(y[i] - y[j])
            cost[i][j] = man * d

    direct = cost[0][n - 1]          # upper bound for answer

    # feasibility test for a given initial time T
    def feasible(T: int) -> bool:
        best = [-1] * n
        best[0] = T
        # max‑heap using negative values
        heap = [(-T, 0)]
        while heap:
            cur_neg, u = heapq.heappop(heap)
            cur = -cur_neg
            if cur != best[u]:
                continue          # outdated entry
            if u == n - 1:
                return True
            for v in range(n):
                if v == u:
                    continue
                c = cost[u][v]
                if c <= cur:
                    new_time = cur - c + gain[v]
                    if new_time > best[v]:
                        best[v] = new_time
                        heapq.heappush(heap, (-new_time, v))
        return False

    lo, hi = 0, direct
    while lo < hi:
        mid = (lo + hi) // 2
        if feasible(mid):
            hi = mid
        else:
            lo = mid + 1
    print(lo)


