import sys

def normalize(s: str):
    i = 0
    tokens = []
    while i < len(s):
        c = s[i]
        if c not in {'u', 'o', 'h', 'k'}:
            tokens.append(c)
            i += 1
        elif c in ('u', 'o'):
            # segment consisting only of 'u' and 'o'
            cnt_o = cnt_u = 0
            while i < len(s) and s[i] in ('u', 'o'):
                if s[i] == 'o':
                    cnt_o += 1
                else:
                    cnt_u += 1
                i += 1
            effective = cnt_o + 2 * cnt_u   # invariant for this segment
            tokens.append(('U', effective))
        else:  # c in ('h', 'k')
            start = i
            cnt_h = 0
            while i < len(s) and s[i] in ('h', 'k'):
                if s[i] == 'h':
                    cnt_h += 1
                i += 1
            segment = s[start:i]
            # trailing k's after the last h
            trailing_k = 0
            for ch in reversed(segment):
                if ch == 'k':
                    trailing_k += 1
                else:  # ch == 'h'
                    break
            tokens.append(('H', cnt_h, trailing_k))
    return tuple(tokens)


